const contract = new ethers.Contract(CONTRACT_ADDRESS, CONTRACT_ABI, wallet); // Connects the contract to the wallet for signing transactions

// --- Functions to Interact with Ethereum ---

/**
 * Sends a specified amount of ETH to a recipient address.
 * @param {string} recipientAddress The address to send ETH to.
 * @param {string} amountEth The amount of ETH to send (e.g., "0.01").
 * @returns {Promise<ethers.TransactionResponse>} The transaction response.
 */
async function sendEth(recipientAddress, amountEth) {
  try {
    console.log(`Attempting to send ${amountEth} ETH from ${wallet.address} to ${recipientAddress}...`);

    const tx = {
      to: recipientAddress,
      value: ethers.parseEther(amountEth), // Convert ETH string to Wei BigInt
      // Optional: Specify gasPrice and gasLimit if needed, otherwise ethers will estimate
      // gasPrice: ethers.parseUnits('20', 'gwei'),
      // gasLimit: 21000, // Standard ETH transfer gas limit
    };

    const transactionResponse = await wallet.sendTransaction(tx);
    console.log('Transaction sent:', transactionResponse.hash);

    // Wait for the transaction to be mined and confirmed
    const receipt = await transactionResponse.wait();
    console.log('Transaction confirmed in block:', receipt.blockNumber);
    console.log('Transaction receipt:', receipt);

    return transactionResponse;
  } catch (error) {
    console.error('Error sending ETH:', error);
    throw error;
  }
}

